export interface Plugin {
  id: string;
  name: string;
  command: string;
  usage: string;
  description: string;
  category: string;
  enabled: boolean;
  cooldown: number;
  usageCount: number;
}

export interface PluginCategory {
  id: string;
  name: string;
  icon: string;
  color: string;
}

